#include <iostream>
#include <string>
#include <algorithm>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string s;
    cin >> s;

    // Sort digits in ascending order
    sort(s.begin(), s.end());

    // Find the first non-zero digit and swap it to the front
    if (s[0] == '0') {
        for (size_t i = 1; i < s.size(); ++i) {
            if (s[i] != '0') {
                swap(s[0], s[i]);
                break;
            }
        }
    }

    cout << s << '\n';
    return 0;
}
